import{_ as a,o as e,c as r,ae as l}from"./chunks/framework.DAK3ioSj.js";const g=JSON.parse('{"title":"SkCC","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skcc.md","filePath":"radar/tech-skcc.md"}'),o={name:"radar/tech-skcc.md"};function i(n,t,d,s,h,c){return e(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="skcc" tabindex="-1">SkCC <a class="header-anchor" href="#skcc" aria-label="Permalink to &quot;SkCC&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 执行 | <strong>成熟度</strong>: 🟡 成长期 | <strong>综合评分</strong>: 0.49</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>跨框架 Skill 编译</strong> —— 引入 <strong>SkIR 强类型 IR</strong> 把 Skill 语义与 Agent 框架格式解耦，让一份 Skill 在 Claude Code / Kimi CLI 等不同框架间可移植部署。</p><p><strong>来源</strong>:</p><ul><li>学术研究</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2605.03353" target="_blank" rel="noreferrer">arXiv 2605.03353</a></li><li>标题：<em>SkCC: Portable and Secure Skill Compilation for Cross-Framework LLM Agents</em></li><li>提交：2026-05-05；最新版：2026-05-09 (v2)</li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="skir-强类型中间表示" tabindex="-1">SkIR：强类型中间表示 <a class="header-anchor" href="#skir-强类型中间表示" aria-label="Permalink to &quot;SkIR：强类型中间表示&quot;">​</a></h3><p>借鉴传统编译器思路：</p><ul><li>Skill 用强类型 IR 表达（与具体 Agent 框架解耦）</li><li>通过 codegen 编译为各框架的原生格式（Claude Code / Kimi CLI / Cursor 等）</li></ul><h3 id="关键数字" tabindex="-1">关键数字 <a class="header-anchor" href="#关键数字" aria-label="Permalink to &quot;关键数字&quot;">​</a></h3><table tabindex="0"><thead><tr><th>框架</th><th style="text-align:center;">接入 SkCC 前</th><th style="text-align:center;">接入后</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td style="text-align:center;">21.1%</td><td style="text-align:center;"><strong>33.3%</strong></td></tr><tr><td><strong>Kimi CLI</strong></td><td style="text-align:center;">35.1%</td><td style="text-align:center;"><strong>48.7%</strong></td></tr></tbody></table><h3 id="填补的空白" tabindex="-1">填补的空白 <a class="header-anchor" href="#填补的空白" aria-label="Permalink to &quot;填补的空白&quot;">​</a></h3><p>这是业界<strong>第一个</strong>直接解决&quot;Skill 在不同 Agent 框架上行为不一致&quot;问题的系统方案 —— Skill-insight 竞品分析中此项被标记为&quot;完全空白&quot;。</p><blockquote><p>同一个 Skill 在 Claude Code 和 OpenCode 上即使格式兼容，执行行为也可能完全不同。SkCC 通过强类型 IR 解决这个问题。</p></blockquote><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="主要能力" tabindex="-1">主要能力 <a class="header-anchor" href="#主要能力" aria-label="Permalink to &quot;主要能力&quot;">​</a></h3><ul><li>Skill IR 强类型抽象</li><li>跨框架自动 codegen</li><li>包含安全性考虑</li></ul><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>学术阶段，未见生产部署</li><li>需要各框架开发对应 codegen target</li><li>不解决 Skill 内容本身的质量问题</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.50</td><td>论文阶段</td></tr><tr><td>创新性</td><td>0.80</td><td>&quot;Skill 编译器&quot;是开创性视角</td></tr><tr><td>落地程度</td><td>0.30</td><td>学术</td></tr><tr><td>生态活跃度</td><td>0.30</td><td>较新（2026-05）</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.49</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2605.03353" target="_blank" rel="noreferrer">SkCC 论文</a></li></ul>',32)])])}const k=a(o,[["render",i]]);export{g as __pageData,k as default};
